        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt(); // Read number of test cases

        while (t-- > 0) {
            int n = sc.nextInt(); // Read size of array
            int k = sc.nextInt(); // Read value of K
            int[] arr = new int[n]; // Array to store the elements
