            for (int i = 0; i < n; i++) {
                arr[i] = sc.nextInt();
                totalSum += arr[i];
            }

            // Sort the array
            Arrays.sort(arr);

            // Sum of the first K smallest numbers (S1) and last K largest numbers (S2)
            long sumOfKSmallest = 0;

            for (int i = 0; i < k; i++) {
                sumOfKSmallest += arr[i];
