const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextLine() {
    return lines[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextInts() {
    return nextLine().split(' ').map(Number);
}

let t = nextInt();

while (t--) {
    let [n, k] = nextInts();
    let arr = nextInts();
    let totalSum = arr.reduce((acc, num) => acc + num, 0);

    // Sort the array
    arr.sort((a, b) => a - b);

    // Sum of the first K smallest numbers
    let sumOfKSmallest = 0;

    for (let i = 0; i < k; i++) {
        sumOfKSmallest += arr[i];
    }

    // Calculate the maximum difference
    let diff1 = Math.abs(sumOfKSmallest - (totalSum - sumOfKSmallest));

    // Output the maximum difference
    console.log(diff1);
}

